import { faPlus, faSquare } from "@fortawesome/free-solid-svg-icons";

import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { Link } from "react-router-dom";
import React from "react";
import { aboutUsData } from "./services/cardsAboutUsData";
import styled from "styled-components";

const SectionContainer = styled.section`
  width: 100%;
  padding-top: 5%;
`;

const Title = styled.h2`
  margin-left: auto;
  margin-right: auto;
  margin-bottom: 20px;
  position: relative;
  display: inline-block;
  font-size: calc(24px * var(--fs, 1));

  @media (max-width: 900px) {
    margin-bottom: 50px;
    font-size: calc(18px * var(--fs, 1));
  }
`;

const CardsContainer = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(300px, 1fr));
  gap: 20px;
  margin-top: 20px;
  width: 100%;
  margin: auto;

  @media (max-width: 900px) {
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    justify-content: flex-end;
    align-items: flex-end;
  }
`;

const Card = styled.div`
  width: 100%;
  height: 180px;
  padding: 20px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  background-color: ${(props) => props.color};
  position: relative;

  @media (max-width: 900px) {
    height: 150px;
  }
`;

const TitleCard = styled.h3`
  color: ${(props) => {
    // Use appropriate text color based on background for WCAG AA compliance
    const bgColor = props.$bgColor || props.color;
    if (bgColor === "#224464") return "#fff"; // Dark blue background → white text
    // Green and light backgrounds need dark text for proper contrast
    return "#000"; // Black text for best contrast on green/light backgrounds
  }};
  font-size: calc(16px * var(--fs, 1));
  text-align: center;
  margin-top: 10px;
  margin-bottom: 20px;
  width: 100%;
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
  font-weight: 700;
  text-shadow: 0 1px 3px rgba(255, 255, 255, 0.3);

  @media (max-width: 768px) {
    font-size: calc(14px * var(--fs, 1));
    margin-bottom: 10px;
  }
`;

const Image = styled.img`
  width: 60px;
  height: 60px;
  margin-bottom: 10px;
`;

const LinkButton = styled(Link)`
  background-color: transparent;
  border: none;
  cursor: pointer;
  position: absolute;
  bottom: 10px;
  right: 10px;
  font-size: calc(20px * var(--fs, 1));
  transition: color 0.3s, transform 0.3s;
  text-decoration: none;
  color: inherit;

  @media (max-width: 768px) {
    font-size: calc(18px * var(--fs, 1));
  }

  &:hover {
    color: #071c2f;
    transform: rotate(90deg);
  }
`;
const ExternalButton = styled.a`
  background-color: transparent;
  border: none;
  cursor: pointer;
  position: absolute;
  bottom: 10px;
  right: 10px;
  font-size: calc(20px * var(--fs, 1));
  transition: color 0.3s, transform 0.3s;
  text-decoration: none;
  color: inherit;

  @media (max-width: 768px) {
    font-size: calc(18px * var(--fs, 1));
  }

  &:hover {
    color: #071c2f;
    transform: rotate(90deg);
  }
`;
const Margin = styled.div`
  width: 100%;
  height: 70px;
  background-color: white;
  @media (max-width: 900px) {
    height: 30px;
  }
`;

const StyledFontAwesomeIcon = styled(FontAwesomeIcon)`
  font-size: calc(30px * var(--fs, 1));

  @media (max-width: 768px) {
    font-size: calc(26px * var(--fs, 1));
  }
`;

const CircleIcon = styled(FontAwesomeIcon)`
  font-size: calc(${(props) => props.size}px * var(--fs, 1));
  color: ${(props) => props.color};
  margin-right: 10px;
`;

const CardsAboutUs = () => {
  return (
    <>
      <SectionContainer>
        <Title>
          <CircleIcon icon={faSquare} size={15} color="#c6b1c9" />
          Sobre nosotros...
        </Title>
        <CardsContainer>
          {aboutUsData.map((card, index) => {
            const bgColor = index === 0 ? "#81b71a" : card.color;
            return (
              <Card key={index} color={bgColor}>
                <TitleCard $bgColor={bgColor} color={card.color}>
                  {card.title}
                </TitleCard>
              <Image
                src={card.image}
                alt={card.alt}
                loading="lazy"
                width="60"
                height="60"
              />
              {(() => {
                // Determine if this should be treated as an internal route or an external/file link.
                const isString = typeof card.url === "string";
                // Consider common document/image extensions and CRA's /static/ path as external assets.
                const isAssetOrFile =
                  isString &&
                  (/\.(pdf|docx?|xlsx?|zip|png|jpe?g|webp|svg)$/i.test(
                    card.url
                  ) ||
                    card.url.includes("/static/"));
                const isInternalRoute =
                  isString && card.url.startsWith("/") && !isAssetOrFile;

                if (isInternalRoute) {
                  return (
                    <LinkButton to={card.url} aria-label={card.ariaLabel} title={card.browserTitle}>
                      <StyledFontAwesomeIcon
                        icon={faPlus}
                        style={{
                          color:
                            card.color === "#224464" ? "#c6b1c9" : "#071c2f",
                        }}
                      />
                    </LinkButton>
                  );
                }

                // External link or asset file → open in new tab
                return (
                  <ExternalButton
                    href={card.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    aria-label={card.ariaLabel}
                    title={card.browserTitle}
                  >
                    <StyledFontAwesomeIcon
                      icon={faPlus}
                      style={{
                        color: card.color === "#224464" ? "#c6b1c9" : "#071c2f",
                      }}
                    />
                  </ExternalButton>
                );
              })()}
            </Card>
            );
          })}
        </CardsContainer>
      </SectionContainer>
      <Margin />
    </>
  );
};

export default CardsAboutUs;
